    if (b == 0) return a;
    return gcd(b, a % b);
}

// Function to perform DFS
void dfs(int node, int parent, int *A, int **edges, int *dist, int *gcd, int *min, int *max, int N) {
    for (int i = 0; i < N; i++) {
        if (edges[node][i] != 0 && i != parent) {
            dist[i] = dist[node] + edges[node][i];
            gcd[i] = gcd(A[node], A[i]);
            min[i] = (A[node] < A[i]) ? A[node] : A[i];
            dfs(i, node, A, edges, dist, gcd, min, max, N);
            *max = (*max > dist[i] * gcd[i] * min[i]) ? *max : dist[i] * gcd[i] * min[i];
        }
    }
}

